  ('locality-e3452428-moex-00139', 'locality-e3452428', 'locality-e3452428-moex-112-b96fcbef', 'sub-locality-e3452428-06', NULL, 'essay', '甲與女友 A 交往 3 年，因 B 的介入，A 遂與甲分手而與 B 訂婚。甲的
好友乙聽聞後非常生氣，覺得應該給這對男女一個小小的教訓，便勸說
本無想法的甲，使甲一氣之下拿取棒球棒找 A、B報復。甲至 A宅等候
一天，因 A、B出遊未遇見，遂作罷返家。次日，甲於下班時間至 A辦
公室埋伏，果見 A、B 手牽手走出來，甲便對其二人一頓暴打，A 手腳
挫傷，B 被擊中後倒下撞及牆角，一眼受傷視力僅剩 0.2（原來視力為
1.0）。又甲見 B的手機掉在地上，覺得這麼貴的手機應該屬於自己才是，
便將其帶走。請問甲、乙的行為如何論處？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:18+00:00", "source_pdf_sha1": "0248787c1f6b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "302", "s": "0803", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法總則與刑法總則", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
